import{_ as t,o as e,c as o,a3 as r}from"./chunks/framework.CRbjHCyB.js";const h=JSON.parse('{"title":"伪编译","description":"","frontmatter":{},"headers":[],"relativePath":"zh/catter/features/fake-compilation.md","filePath":"zh/catter/features/fake-compilation.md"}'),i={name:"zh/catter/features/fake-compilation.md"};function l(n,a,s,c,p,d){return e(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="伪编译" tabindex="-1">伪编译 <a class="header-anchor" href="#伪编译" aria-label="Permalink to &quot;伪编译&quot;">​</a></h1><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p>此功能尚在计划中，尚未实现。</p></div><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><p>伪编译不将编译任务转发给真正的编译器，而是由 catter 生成占位的 <code>.o</code> 文件。这样构建系统可以完成完整的运行流程（包括链接步骤），而无需实际编译。</p><p>带来的好处：</p><ul><li><strong>在极短时间内获得完整的 CDB。</strong> 不执行真正的编译工作，构建速度仅受构建系统调度能力的限制。</li><li><strong>完整的链接器命令捕获。</strong> 由于占位目标文件存在于磁盘上，链接器调用可以正常进行并被拦截。</li></ul><h2 id="智能依赖分析" tabindex="-1">智能依赖分析 <a class="header-anchor" href="#智能依赖分析" aria-label="Permalink to &quot;智能依赖分析&quot;">​</a></h2><p>并非所有命令都可以伪造。代码生成器（如 LLVM TableGen）必须真正执行构建，因为它们生成的头文件是其他编译步骤的输入。</p><p>Catter 将通过依赖分析区分以下两类：</p><ul><li><strong>常规编译</strong> -- 可以伪造。输出的 <code>.o</code> 文件仅被链接器消费。</li><li><strong>代码生成器</strong> -- 必须真正构建。其输出（生成的头文件、源文件）是其他编译步骤所需的输入。</li></ul><p>这实现了&quot;最小构建&quot;：仅构建 CDB 生成和头文件产出所严格需要的部分，其余全部伪造。</p>',11)])])}const _=t(i,[["render",l]]);export{h as __pageData,_ as default};
